code = """import json

# Book info: list of dicts with 'book_id', 'title'
book_info_list = locals()['var_function-call-13950280173143468074']
# Reviews: list of dicts with 'purchase_id', 'rating', 'review_time'
reviews = locals()['var_function-call-9158178241970306828']

# Create a map from purchase_id to list of ratings
rating_map = {}
for review in reviews:
    pid = review['purchase_id']
    rating = float(review['rating'])
    if pid not in rating_map:
        rating_map[pid] = []
    rating_map[pid].append(rating)

# Calculate average ratings and filter
valid_purchase_ids = []
for pid, ratings in rating_map.items():
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating >= 4.5:
        valid_purchase_ids.append(pid)

# Convert purchase_ids back to book_ids
valid_book_ids = set([pid.replace('purchaseid_', 'bookid_') for pid in valid_purchase_ids])

# Get titles
valid_titles = []
for book in book_info_list:
    if book['book_id'] in valid_book_ids:
        valid_titles.append(book['title'])

print("__RESULT__:")
print(json.dumps(valid_titles))"""

